import { useNavigate, Link } from "react-router-dom";
import { Image, Form} from 'react-bootstrap'
import MainLayout from "../../components/Layout";
import BASE_URL from "../../config";

function AddOffice() {
  const [offices, setOffices] = useState([]);
  const [errors, setErrors] = useState({});

   const [officelevels, setOfficeLevels] = useState([]);
   const [selectedOfficeLevel, setSelectedOfficeLevel] = useState("");
   const [reportingoffice, setReportingOffice] = useState([]);
   const [selectedReportingOffice, setSelectedReportingOffice] = useState("");
   const [states, setStates] = useState([]);
   const [selectedState, setSelectedState] = useState("");
   const [district, setDistrict] = useState([]);
   const [selectedDistrict, setSelectedDistrict] = useState("");

   const [office, setOffice] = useState({ office_name: "", office_name_local: "", office_level_id: 0,reporting_office_id: "", state_id: 0, district_id: 0,
       mobile: "", email: "",action: "S", status: "A", });

useEffect(() => {
  loadOfficeLevels();
  loadStates();
  loadOfficeList();
}, []);

const loadOfficeList = async () => {
  try {
    const response = await fetch(`${BASE_URL}/user/getoffices`);
    const data = await response.json();
    setOffices(data);
  } catch (err) {
    console.log(err);
  }
};
const loadOfficeLevels = async () => {
  try {
    const response = await fetch(`${BASE_URL}/user/get-officelevel`);
    const data = await response.json();
    setOfficeLevels(data);
  } catch (err) {
    console.log(err);
  }
};
const loadStates = async () => {
  try {
    const response = await fetch(`${BASE_URL}/user/get-state`);
    const data = await response.json();
    setStates(data);
  } catch (err) {
    console.log(err);
  }
};
const loadReportingOffice = async (OfficeLevelID) => {
   console.log("OfficeLevelID:", OfficeLevelID);
  console.log("payload:", JSON.stringify({
    office_level_id: Number(OfficeLevelID),
  }));

  try {
    const response = await fetch(`${BASE_URL}/user/get-reportingoffice`,
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          office_level_id: Number(OfficeLevelID),
        }),
      }
    );

    const data = await response.json();
    setReportingOffice(data);
  } catch (err) {
    console.log(err);
  }
};
const loadDistrict = async (StateID) => {
  try {
    const response = await fetch(`${BASE_URL}/user/get-district`,
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          state_id: Number(StateID),
        }),
      }
    );

    const data = await response.json();
    setDistrict(data);
  } catch (err) {
    console.log(err);
  }
};
const validateForm = () => {
  let tempErrors = {};

  // Office Name
  if (!office.office_name.trim()) {
    tempErrors.office_name = "Office name is required";
  }

  // Office Level
  if (!office.office_level_id || office.office_level_id === 0) {
    tempErrors.office_level_id = "Please select office level";
  }

  // Reporting Office validation only if office level > 10
  if (Number(office.office_level_id) > 10 && (!office.reporting_office_id || office.reporting_office_id.trim() === "") ) {
    tempErrors.reporting_office_id = "Please select reporting office";
  }

  // State
  if (!office.state_id || office.state_id === 0) {
    tempErrors.state_id = "Please select state";
  }

  // District
  if (!office.district_id || office.district_id === 0) {
    tempErrors.district_id = "Please select district";
  }

  // Mobile
  if (!office.mobile.trim()) {
    tempErrors.mobile = "Mobile number is required";
  } else if (!/^[0-9]{10}$/.test(office.mobile)) {
    tempErrors.mobile = "Mobile number must be 10 digits";
  }

  // Email
  if (!office.email.trim()) {
    tempErrors.email = "Email is required";
  } else if (
    !/^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i.test(office.email)
  ) {
    tempErrors.email = "Invalid email address";
  }

  setErrors(tempErrors);

  return Object.keys(tempErrors).length === 0;
};
const saveOffice = async (e) => {
  e.preventDefault();
  if (!validateForm()) {
    return;
  }
  try {
    const response = await fetch(`${BASE_URL}/user/addupdateoffice`,
      {
        method: "POST",
        credentials: "include",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(office),
      }
    );

    const data = await response.json();

    if (response.ok) {
      let message = "Office Details Saved Successfully";

      if (office.action === "U") {
        message = "Office updated successfully";
      }

      if (office.action === "R") {
        message = "Office deleted successfully";
      }
      alert(message);
      loadOfficeList();
      // Clear form
      setOffice({office_name: "", office_name_local: "", office_level_id: 0,reporting_office_id:"", address: "", state_id: 0, district_id: 0, mobile: "", email: "",});

      setSelectedOfficeLevel("");
      setSelectedReportingOffice("");
      setSelectedState("");
      setSelectedDistrict("");
      setDistrict([]);
    } else {
      alert(data.message || "Failed to save office");
    }
  } catch (err) {
    console.log(err);
    alert("Error while saving office");
  }
};

const handleEdit = (b) => {

  setOffice({
    office_id: b.office_id,
    office_name: b.office_name,
    office_name_local: b.office_name_local,
    office_level_id: b.office_level_id,
    reporting_office_id: b.reporting_office_id,
    address: b.address,
    state_id: b.state_id,
    district_id: b.district_id,
    mobile: b.mobile,
    email: b.email,
    action: "U",
    status: "A",
  });

  setSelectedOfficeLevel(b.office_level_id);
  loadReportingOffice(b.office_level_id)
  setSelectedReportingOffice(b.reporting_office_id);
  setSelectedState(b.state_id);
  loadDistrict(b.state_id);
  setSelectedDistrict(b.district_id);
};

const handleDelete = async (officeID) => {
  const confirmDelete = window.confirm(
    "Are you sure you want to delete?"
  );
  if (!confirmDelete) {
    return;
  }

  try {
    const deleteOffice = {office_id: officeID,action: "R", status: "D",
    };
    const response = await fetch(`${BASE_URL}/user/addupdateoffice`,
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        credentials:"include",
        body: JSON.stringify(deleteOffice),
      }
    );

    const data = await response.json();
    if (response.ok) {
      alert("Office deleted successfully");
      loadOfficeList();
    } else {
      alert(data.message || "Delete failed");
    }

  } catch (err) {
    console.log(err);
    alert("Error while deleting office");
  }
};

const handleReset = (b) => {

   setOffice({
      office_name: "",
      office_name_local: "",
      office_level_id: 0,
      reporting_office_id:"",
      address: "",
      state_id: 0,
      district_id: 0,
      mobile: "",
      email: "",
      action: "",
      status: "",
      });

      setSelectedOfficeLevel("");
      loadReportingOffice("")
      setSelectedReportingOffice("");
      setSelectedState("");
      loadDistrict(0);
      setSelectedDistrict("");
      setDistrict([]);
      setErrors({});
};

  return (

    <MainLayout>

      <div className="conatiner-fluid content-inner mt-n5 px-2 py-0">
        <div className="row py-3">
                  <div class="col-lg-3 col-md-6">
                 <div class="card border-bottom border-4 border-0 border-primary">
                    <div class="card-body">
                       <div class="d-flex justify-content-between align-items-center">
                          <div>
                            <span>Total Office</span>
                          </div>
                          <div>
                            <span>4</span>
                          </div>
                        </div>
                    </div>
                 </div>
              </div>
              <div class="col-lg-3 col-md-6">
                 <div class="card border-bottom border-4 border-0 border-info">
                    <div class="card-body">
                       <div class="d-flex justify-content-between align-items-center">
                          <div>
                            <span>Headquarters</span>
                          </div>
                          <div>
                            <span>1</span>
                          </div>
                        </div>
                    </div>
                 </div>
              </div>
              <div class="col-lg-3 col-md-6">
                 <div class="card border-bottom border-4 border-0 border-danger">
                    <div class="card-body">
                       <div class="d-flex justify-content-between align-items-center">
                          <div>
                            <span>Regional Office</span>
                          </div>
                          <div>
                            <span>1</span>
                          </div>
                        </div>
                    </div>
                 </div>
              </div>
              <div class="col-lg-3 col-md-6">
                 <div class="card border-bottom border-4 border-0 border-warning">
                    <div class="card-body">
                       <div class="d-flex justify-content-between align-items-center">
                          <div>
                            <span>District Office</span>
                          </div>
                          <div>
                            <span>2</span>
                          </div>
                        </div>
                    </div>
                 </div>
              </div>
                </div>
         <div className="row py-3">
          <div class="col-xl-2 col-lg-4">
               <div class="card">
                  <div class="card-header d-flex justify-content-between border-0">
                     <div class="header-title">
                        <h5 class="card-title">Instructions</h5>
                     </div>
                  </div>
                  <div class="card-body">
                    <ol className="form-label col-form-label col-form-label-sm text-danger">
                      <li>Here you can add Office along with its basic details.</li>
                      <li>You can also update office details.</li>
                      <li>All fiels marked <span style={{color: "Red"}}>*</span> are mandatory.</li>
                      <li>If the office level is Headquarters, then selecting a reporting office is not required. For all other office levels, 
                        the reporting office field is mandatory.</li>
                    </ol>
                    </div>
                    </div>
                  </div>
            <div className="col-xl-4 col-lg-3">
               <div className="card">
            <div className="card-header d-flex justify-content-between border-0">
               <div className="header-title">
                  <h5 className="card-title">Office List</h5>
               </div>
            </div>
            <div className="card-body px-0">
               <div className="table-responsive">
                  <table id="user-list-table" className="table table-striped form-label col-form-label col-form-label-sm" role="grid" data-bs-toggle="data-table">
                     <thead>
                        <tr className="ligth">
                           <th>Office Name</th>
                           {/* <th>Office Name (Local)</th> */}
                           <th>Office Level</th>
                           <th>Contact No.</th>
                           <th>Email</th>
                           <th style={{minWidth: "100px"}}>Action</th>
                        </tr>
                     </thead>
                     <tbody>
                        {offices.map((b) => (
                        <tr key={b.office_id}>
                           <td>{b.office_name}</td>
                           {/* <td>{b.office_name_local}</td> */}
                           <td>{b.office_level_name}</td>
                           <td>{b.mobile}</td>
                           <td>{b.email}</td>
                           <td>
                              <div className="flex align-items-center list-user-action">
                                 <a className="btn btn-sm btn-icon btn-warning" data-bs-toggle="tooltip" data-bs-placement="top" title="Edit" data-original-title="Edit" onClick={() => handleEdit(b)}>
                                    <i className="fa fa-edit"></i>
                                 </a>&nbsp;
                                 <a className="btn btn-sm btn-icon btn-danger" data-bs-toggle="tooltip" data-bs-placement="top" title="Delete" onClick={() => handleDelete(b.office_id)}>
                                    <span className="btn-inner">
                                       <i className="fa fa-trash"></i>
                                    </span>
                                 </a>
                              </div>
                           </td>
                        </tr>
                        ))}
                        </tbody>
                        </table>
                        </div>
                        </div>
                        </div>
            </div>
            <div className="col-xl-6 col-lg-6">
               <div className="card">
                  <div className="card-header d-flex justify-content-between border-0">
                     <div className="header-title">
                        <h5 className="card-title">Add New Office</h5>
                     </div>
                  </div>
                  <div className="card-body">
                     <div className="new-user-info">
                        <Form onSubmit={saveOffice}>
                           <h6 class="mb-3">1. General Details</h6>
                           <div className="row">
                              <div className="form-group col-md-6">
                                 <label className="form-label col-form-label col-form-label-sm" for="fname">Name <span style={{color: "Red"}}>*</span></label>
                                 <input type="text" className={`form-control form-control-sm ${errors.office_name ? "is-invalid" : ""}`} id="tbofficename" placeholder="Enter Office Name" 
                                 value={office.office_name} onChange={(e) => setOffice({ ...office, office_name: e.target.value }) } />
                                 <div className="invalid-feedback">{errors.office_name}</div>
                              </div>
                              <div className="form-group col-md-6">
                                 <label className="form-label col-form-label col-form-label-sm" for="lname">Name (Local)</label>
                                 <input type="text" className="form-control form-control-sm" id="tbofficenamelocal" placeholder="Enter Office Name (Local)" 
                                 value={office.office_name_local} onChange={(e) => setOffice({ ...office, office_name_local: e.target.value }) } />
                              </div>
                              <div className="form-group col-sm-6">
                                 <label className="form-label col-form-label col-form-label-sm">Level <span style={{color: "Red"}}>*</span></label>
                                 <select className={`selectpicker form-control form-control-sm ${errors.office_level_id ? "is-invalid" : ""}`} data-style="py-0"  value={selectedOfficeLevel}  
                                 onChange={(e) => { const OfficeLevelID = e.target.value; setSelectedOfficeLevel(OfficeLevelID); loadReportingOffice(OfficeLevelID);
                                    setOffice({ ...office, office_level_id: parseInt(e.target.value, 10), }); }}>
                              <option value="">Select Office Level</option>
                                 {officelevels.map((level) => (
                                    <option key={level.office_level_id} value={level.office_level_id} >
                                       {level.office_level_name}
                                    </option>
                                 ))}
                           </select>
                           <div className="invalid-feedback">{errors.office_level_id}</div>
                              </div>
                              <div className="form-group col-sm-6">
                                 <label className="form-label col-form-label col-form-label-sm">Reporting Office</label>
                                 <select className={`selectpicker form-control form-control-sm ${errors.reporting_office_id ? "is-invalid" : ""}`} data-style="py-0"  value={selectedReportingOffice}  
                                 onChange={(e) => { setSelectedReportingOffice(e.target.value); setOffice({ ...office, reporting_office_id: e.target.value, }); }}>
                              <option value="">Select Reporting Office</option>
                                 {reportingoffice.map((level) => (
                                    <option key={level.office_id} value={level.office_id} >
                                       {level.office_name}
                                    </option>
                                 ))}
                           </select>
                           <div className="invalid-feedback">{errors.reporting_office_id}</div>
                              </div>
                              </div>
                              <hr />
                           <h6 class="mb-3">2. Contact Details</h6>
                           <div class="row">
                              <div className="form-group col-md-12">
                                 <label className="form-label col-form-label col-form-label-sm" for="add1">Address </label>
                                 <input type="text" className="form-control form-control-sm" id="tbaddress" placeholder="Enter Address"
                                 value={office.address} onChange={(e) => setOffice({ ...office, address: e.target.value }) }  />
                              </div>
                              <div className="form-group col-sm-6">
                                 <label className="form-label col-form-label col-form-label-sm">State <span style={{color: "Red"}}>*</span></label>
                                 <select className={`selectpicker form-control form-control-sm ${errors.state_id ? "is-invalid" : ""}`} data-style="py-0" value={selectedState} 
                                 onChange={(e) => { const StateID = e.target.value; setSelectedState(StateID); loadDistrict(StateID);
                                    setOffice({ ...office, state_id: parseInt(e.target.value, 10), }); }}>
                                       <option value="">Select State</option>
                                       {states.map((state) => (
                                          <option key={state.state_id} value={state.state_id}>
                                             {state.state_name}
                                          </option>
                                       ))}
                                 </select>
                                 <div className="invalid-feedback">{errors.state_id}</div>
                              </div>
                              <div className="form-group col-sm-6">
                                 <label className="form-label col-form-label col-form-label-sm">District <span style={{color: "Red"}}>*</span></label>
                                 <select className={`selectpicker form-control form-control-sm ${errors.district_id ? "is-invalid" : ""}`} data-style="py-0" value={selectedDistrict} 
                                 onChange={(e) => {setSelectedDistrict(e.target.value); setOffice({ ...office, district_id: parseInt(e.target.value, 10), }) }}>
                                       <option value="">Select District</option>
                                       {district.map((d) => (
                                          <option key={d.district_id} value={d.district_id}>
                                             {d.district_name}
                                          </option>
                                       ))}
                                       </select>
                                       <div className="invalid-feedback">{errors.district_id}</div>
                              </div>
                              <div className="form-group col-md-6">
                                 <label className="form-label col-form-label col-form-label-sm" for="mobno">Contact Number<span style={{color: "Red"}}>*</span> </label>
                                 <input type="text" className={`form-control form-control-sm ${errors.mobile ? "is-invalid" : ""}`} id="tbmobileno" placeholder="Max. 15 Characters"
                                 value={office.mobile} maxLength={15} onChange={(e) =>{ const value = e.target.value.replace(/\D/g, "").slice(0, 15);
                                  setOffice({ ...office, mobile: value }) }} />
                                 <div className="invalid-feedback">{errors.mobile}</div>
                              </div>
                              <div className="form-group col-md-6">
                                 <label className="form-label col-form-label col-form-label-sm" for="email">Email<span style={{color: "Red"}}>*</span></label>
                                 <input type="email" className={`form-control form-control-sm ${errors.email ? "is-invalid" : ""}`} id="tbemail" placeholder="email@example.com"
                                 value={office.email} onChange={(e) => setOffice({ ...office, email: e.target.value }) } />
                                 <div className="invalid-feedback">{errors.email}</div>
                              </div>
                           </div>
                           <hr />
                           <h6 class="mb-3">3. Nodel Officer Details</h6>
                           <div class="row">
                              <div className="form-group col-md-12">
                                 <label className="form-label col-form-label col-form-label-sm" for="add1">Name <span style={{color: "Red"}}>*</span></label>
                                 <input type="text" className="form-control form-control-sm" id="tbnodelname" placeholder="Office Address"
                                 value={office.address} onChange={(e) => setOffice({ ...office, address: e.target.value }) }  />
                              </div>
                              <div className="form-group col-md-6">
                                 <label className="form-label col-form-label col-form-label-sm" for="mobno">Mobile Number<span style={{color: "Red"}}>*</span></label>
                                 <input type="text" className={`form-control form-control-sm ${errors.mobile ? "is-invalid" : ""}`} id="tbnodelmobileno" placeholder="Max. 10 Characters"
                                 value={office.mobile} maxLength={10} onChange={(e) =>{ const value = e.target.value.replace(/\D/g, "").slice(0, 15);
                                  setOffice({ ...office, mobile:value }) }} />
                                 <div className="invalid-feedback">{errors.mobile}</div>
                              </div>
                              <div className="form-group col-md-6">
                                 <label className="form-label col-form-label col-form-label-sm" for="email">Email<span style={{color: "Red"}}>*</span></label>
                                 <input type="email" className={`form-control form-control-sm ${errors.email ? "is-invalid" : ""}`} id="tbnodelemail" placeholder="email@example.com"
                                 value={office.email} onChange={(e) => setOffice({ ...office, email: e.target.value }) } />
                                 <div className="invalid-feedback">{errors.email}</div>
                              </div>
                           </div>
                           <button type="submit" className="btn btn-primary"><i className="fa fa-check"></i> {office.action === "U" ? "Update" : "Save"} </button>&nbsp;&nbsp;
                           <button type="button" className="btn btn-danger" onClick={() => handleReset()}><i className="fa fa-times"></i> Cancel </button>
                        </Form>
                     </div>
                  </div>
               </div>
            </div>
         </div>
      </div>
    </MainLayout>
 );
}

export default AddOffice;
